mapper.select:
select ss.seat_id, ss.room_id, ss.building_id, ss.seat_no, ss.row_index, ss.col_index, ss.tags, ss.status, ss.assigned_major, c.room_name, tb.building_name, case when exists ( select 1 from reservation_demo.smart_seat_reservation sr where sr.seat_id = ss.seat_id and sr.reservation_date = #{reservation_date} and sr.status in ('待签到','已签到') and sr.start_time = #{start_time} ) then '1' else '0' end occupied from reservation_demo.smart_seat ss join reservation_demo.classroom c on ss.room_id = c.room_id and ss.building_id = c.building_id join reservation_demo.t_building tb on c.building_id = tb.building_id where ss.room_id = #{room_id}
and ss.tags like concat('%', #{tag}, '%')
order by ss.row_index, ss.col_index

mapper.update:
update reservation_demo.smart_seat_reservation
set status = #{status},
    checkin_time = #{checkin_time}
where reservation_id = #{reservation_id}

update reservation_demo.student
set credit_score = #{credit_score}
where s_id = #{s_id}
